9	const COMPONENT_BLOCK_PREMIUM = 60;
10	const CURSED_SURCHARGE_RATE = 0.5;
11	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
12	const HIGH_ENCHANTMENT_THRESHOLD = 5;
13	const LOYALTY_DISCOUNT_RATE = 0.2;
14	const LOYALTY_THRESHOLD = 2;
15	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
16	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
17	const PROCESSING_FEE = 5;
18	
19	interface Item {
20	  type: string;
21	  cursed?: boolean;
22	  enchantment?: number;
23	}
24	
25	function isComponent(type: string): boolean {
26	  return !(type in BASE_PREMIUMS);
27	}
28	
29	function mainItemPremium(items: Item[]): number {
30	  return items
31	    .filter((item) => !isComponent(item.type))
32	    .reduce((sum, item) => sum + itemBasePremium(item), 0);
33	}
34	
35	function componentCounts(items: Item[]): Map<string, number> {
36	  const counts = new Map<string, number>();
37	  for (const item of items) {
38	    if (isComponent(item.type)) {
39	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
40	    }
41	  }
42	  return counts;
43	}
44	
45	function componentPremium(items: Item[]): number {
46	  return [...componentCounts(items).values()].reduce(
47	    (total, count) => total + (count === 3 ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM),
48	    0,
49	  );
50	}
51	
52	function itemBasePremium(item: Item): number {
53	  return BASE_PREMIUMS[item.type] ?? COMPONENT_PREMIUM;
54	}
55	
56	function singleItemSurcharge(item: Item): number {
57	  const base = itemBasePremium(item);
58	  return (item.cursed ? base * CURSED_SURCHARGE_RATE : 0)
59	    + ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
60	}
61	
62	function itemSurcharges(items: Item[]): number {
63	  return items.reduce((sum, item) => sum + singleItemSurcharge(item), 0);
64	}
65	
66	function computeQuotePremium(items: Item[], customer: { yearsWithMHPCO: number }, isFollowUp: boolean): number {
67	  const basePremium = mainItemPremium(items) + componentPremium(items);
68	  const surcharges = itemSurcharges(items);
69	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
70	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
71	  const followUpDiscount = isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
72	  return Math.ceil(basePremium + surcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
73	}
74	
75	export function processScenario(scenario: { customer: { yearsWithMHPCO: number }; steps: Array<{ op: string; items?: Item[] }> }) {
76	  const results = scenario.steps.map((step, index) => {
77	    return { premium: computeQuotePremium(step.items ?? [], scenario.customer, index > 0) };
78	  });
79	  return { results };
80	}
